'use strict';
const path = require('path');
let findRoot = require('find-root');

const ROOT = findRoot(module.filename);

let instance;

const TestConfiguration = require('../lib/jibo-cai-utils').TestConfiguration;

describe('TestConfiguration', () => {

	it('Creating', () => {
		let instance = new TestConfiguration('bla');
		return instance.init(path.join(ROOT, 'resources_test', ''))
			.then( () => {
				expect(instance.namespace).to.equal('bla');
			});
	});

	it('Getting boolean from test files', () => {
		let instance = new TestConfiguration('bla');
		return instance.init(path.join(ROOT, 'resources_test', 'testConfigEnabledA.json'))
			.then( () => {
				return Promise.all([
					instance.getBooleanFromTestConfig('someBoolA', () => Promise.resolve(false)),
					instance.getBooleanFromTestConfig('someBoolB', () => false),
					instance.getBooleanFromTestConfig('someBoolC', () => Promise.resolve(false)),
					instance.getBooleanFromTestConfig('someBoolD', () => false),
					instance.getBooleanFromTestConfig('someBoolE', () => Promise.resolve(false)),
				]);
			}).then( vals => {
				// Expect the values to be like in the test file
				expect(vals).to.deep.equal([true, false, true, false, false]);
			});
	});

	function createTestCase(configName) {
		let instance = new TestConfiguration('bla');
		return {
			instance,
			init() {
				return instance.init(path.join(ROOT, 'resources_test', configName));
			},
			getValues() {
				return Promise.all([
					instance.getBooleanFromTestConfig('bool', () => false),
					instance.getNumberFromTestConfig('num', () => 100),
					instance.getStringFromTestConfig('str', () => 'b'),
					instance.getStringFromTestConfig('str2', () => Promise.resolve('c')),
				]);
			}
		};
	}

	it('Getting all types from test files', () => {
		const test = createTestCase('testConfigEnabledB.json');
		return test.init()
			.then( () => test.getValues() )
			.then( vals => {
				// Expect the values to be like in the test file
				expect(vals).to.deep.equal([true, 33, 'bla', 'c']);
			});
	});

	it('Overriding test options', () => {
		const test = createTestCase('testConfigEnabledB.json');
		return test.init()
			.then( () => {
				test.instance.setOverridingTestConfig({
					bool: false,
					str: 'd'
				});
				return test.getValues();
			}).then( vals => {
				// Expect the values to be overridden
				expect(vals).to.deep.equal([false, 33, 'd', 'c']);
				test.instance.clearOverridingTestConfig();
				return test.getValues();
			}).then( vals => {
				// Expect the original values
				expect(vals).to.deep.equal([true, 33, 'bla', 'c']);
			});
	});

	it('Loading disabled test file', () => {
		const test = createTestCase('testConfigDisabledB.json');
		return test.init()
			.then( () => test.getValues() )
			.then( vals => {
				// Expect the values to be like in the test file
				expect(vals).to.deep.equal([false, 100, 'b', 'c']);
			});
	});

	it('Waiting for event', () => {
		let instance = new TestConfiguration('bla');
		let pr = instance.waitForEvent('test');
		instance.emit('test');
		return pr;
	});

});
